-- Fase 93: laboratório governado; plano e evidência, nunca alteração automática da plataforma.
create table if not exists public.media_experiments(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,
 learning_cycle_id uuid not null references public.meta_andromeda_learning_cycles(id) on delete restrict,name text not null,hypothesis text not null,
 platform text not null check(platform in('meta','google_ads','youtube','tiktok_ads','portal')),single_variable text not null check(single_variable in('audience','creative','placement','optimization_event')),
 control_key text not null,test_key text not null,primary_metric text not null check(primary_metric in('qualified_lead_rate','visit_rate','proposal_rate','win_rate')),
 guardrail_metric text not null check(guardrail_metric in('cpl','invalid_contact_rate','opt_out_rate','complaint_rate')),
 budget_cap numeric(14,2) not null check(budget_cap>0),daily_budget_cap numeric(14,2) not null check(daily_budget_cap>0 and daily_budget_cap<=budget_cap),
 minimum_leads_per_arm integer not null default 50 check(minimum_leads_per_arm between 30 and 10000),minimum_days integer not null default 7 check(minimum_days between 7 and 30),maximum_days integer not null check(maximum_days between 7 and 45 and maximum_days>=minimum_days),
 maximum_guardrail_increase_percent numeric(6,2) not null default 20 check(maximum_guardrail_increase_percent between 0 and 100),status text not null default 'draft' check(status in('draft','approved','running','paused','completed','stopped','rejected','cancelled')),
 external_experiment_key text,created_by uuid not null references public.profiles(id),approved_by uuid references public.profiles(id),approval_reason text,approved_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),
 check(char_length(trim(name)) between 3 and 120 and char_length(trim(hypothesis)) between 20 and 1000 and control_key<>test_key)
);
create table if not exists public.media_experiment_checkpoints(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,experiment_id uuid not null references public.media_experiments(id) on delete cascade,
 elapsed_days integer not null check(elapsed_days>=0),control_spend numeric(14,2) not null check(control_spend>=0),test_spend numeric(14,2) not null check(test_spend>=0),control_leads integer not null check(control_leads>=0),test_leads integer not null check(test_leads>=0),
 control_conversions integer not null check(control_conversions between 0 and control_leads),test_conversions integer not null check(test_conversions between 0 and test_leads),control_guardrail_rate numeric(8,4) not null check(control_guardrail_rate between 0 and 100),test_guardrail_rate numeric(8,4) not null check(test_guardrail_rate between 0 and 100),
 assessment jsonb not null,evidence_hash text not null check(evidence_hash~'^[a-f0-9]{64}$'),recorded_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(organization_id,experiment_id,evidence_hash)
);
create table if not exists public.media_experiment_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,experiment_id uuid not null references public.media_experiments(id) on delete cascade,event_type text not null,from_status text,to_status text,reason text not null,actor_id uuid not null references public.profiles(id),created_at timestamptz not null default now());
create index if not exists media_experiments_org_idx on public.media_experiments(organization_id,status,created_at desc);create index if not exists media_experiment_checkpoints_idx on public.media_experiment_checkpoints(organization_id,experiment_id,created_at desc);
alter table public.media_experiments enable row level security;alter table public.media_experiment_checkpoints enable row level security;alter table public.media_experiment_events enable row level security;
drop policy if exists media_experiments_leadership_read on public.media_experiments;create policy media_experiments_leadership_read on public.media_experiments for select to authenticated using(organization_id=(select public.current_organization_id()) and exists(select 1 from public.profiles p where p.id=auth.uid() and coalesce(p.commercial_role,case when p.role='admin' then 'director' else p.role end) in('director','superintendent')));
drop policy if exists media_experiment_checkpoints_leadership_read on public.media_experiment_checkpoints;create policy media_experiment_checkpoints_leadership_read on public.media_experiment_checkpoints for select to authenticated using(organization_id=(select public.current_organization_id()) and exists(select 1 from public.profiles p where p.id=auth.uid() and coalesce(p.commercial_role,case when p.role='admin' then 'director' else p.role end) in('director','superintendent')));
drop policy if exists media_experiment_events_leadership_read on public.media_experiment_events;create policy media_experiment_events_leadership_read on public.media_experiment_events for select to authenticated using(organization_id=(select public.current_organization_id()) and exists(select 1 from public.profiles p where p.id=auth.uid() and coalesce(p.commercial_role,case when p.role='admin' then 'director' else p.role end) in('director','superintendent')));
revoke all on public.media_experiments,public.media_experiment_checkpoints,public.media_experiment_events from anon,authenticated;grant select on public.media_experiments,public.media_experiment_checkpoints,public.media_experiment_events to authenticated;
create or replace function public.decide_media_experiment(p_actor_id uuid,p_organization_id uuid,p_experiment_id uuid,p_decision text,p_reason text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_status text;begin
 if not exists(select 1 from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true and coalesce(commercial_role,case when role='admin' then 'director' else role end)='director')then raise exception 'experiment_director_required';end if;
 if p_decision not in('approved','rejected')or char_length(trim(coalesce(p_reason,'')))<20 then raise exception 'experiment_decision_invalid';end if;
 update public.media_experiments e set status=p_decision,approved_by=p_actor_id,approval_reason=trim(p_reason),approved_at=now(),updated_at=now() where e.id=p_experiment_id and e.organization_id=p_organization_id and e.status='draft' and exists(select 1 from public.meta_andromeda_learning_cycles c where c.id=e.learning_cycle_id and c.organization_id=p_organization_id and c.status='approved') returning e.status into v_status;
 if v_status is null then raise exception 'experiment_not_decidable';end if;insert into public.media_experiment_events(organization_id,experiment_id,event_type,from_status,to_status,reason,actor_id)values(p_organization_id,p_experiment_id,p_decision,'draft',v_status,trim(p_reason),p_actor_id);return jsonb_build_object('experimentId',p_experiment_id,'status',v_status,'externalChangeExecuted',false,'automaticBudgetChange',false);end$$;
revoke all on function public.decide_media_experiment(uuid,uuid,uuid,text,text) from public,anon,authenticated;grant execute on function public.decide_media_experiment(uuid,uuid,uuid,text,text) to service_role;
create or replace function public.transition_media_experiment(p_actor_id uuid,p_organization_id uuid,p_experiment_id uuid,p_action text,p_external_key text,p_reason text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_from text;v_to text;begin
 if not exists(select 1 from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true and coalesce(commercial_role,case when role='admin' then 'director' else role end)='director')then raise exception 'experiment_director_required';end if;if char_length(trim(coalesce(p_reason,'')))<20 then raise exception 'experiment_transition_reason_required';end if;
 select status into v_from from public.media_experiments where id=p_experiment_id and organization_id=p_organization_id for update;if v_from is null then raise exception 'experiment_not_found';end if;
 v_to:=case when p_action='start'and v_from='approved'and char_length(trim(coalesce(p_external_key,'')))>=5 then'running' when p_action='pause'and v_from='running'then'paused' when p_action='resume'and v_from='paused'then'running' when p_action='stop'and v_from in('running','paused')then'stopped' when p_action='complete'and v_from in('running','paused')then'completed' else null end;if v_to is null then raise exception 'experiment_transition_invalid';end if;
 update public.media_experiments set status=v_to,external_experiment_key=coalesce(nullif(trim(p_external_key),''),external_experiment_key),updated_at=now() where id=p_experiment_id;insert into public.media_experiment_events(organization_id,experiment_id,event_type,from_status,to_status,reason,actor_id)values(p_organization_id,p_experiment_id,p_action,v_from,v_to,trim(p_reason),p_actor_id);return jsonb_build_object('experimentId',p_experiment_id,'status',v_to,'externalChangeExecuted',false,'externalExecutionRecorded',p_action='start');end$$;
revoke all on function public.transition_media_experiment(uuid,uuid,uuid,text,text,text) from public,anon,authenticated;grant execute on function public.transition_media_experiment(uuid,uuid,uuid,text,text,text) to service_role;
